class TestPipelineFailureExemptPrune(unittest.TestCase):
    def test_exempt_on_pipeline_failure_keyword_in_rationale(self):
        state = {"rationale": "2026-05-29 · crypto-momentum: PIPELINE_FAILURE_SUSPECTED — SILENT 45d, 0 placement attempts."}
        self.assertTrue(heuristic_pipeline_failure_exempt_prune("crypto-momentum", state))
    def test_exempt_on_explicit_flag_in_state(self):
        state = {"rationale": "some other rationale", "pipeline_failure_suspected": True}
        self.assertTrue(heuristic_pipeline_failure_exempt_prune("crypto-momentum", state))
    def test_not_exempt_on_normal_zombie_prune_rationale(self):
        state = {"rationale": "AUTO-PRUNED: SILENT 25 days >= 21, 0 trades lifetime. v3.11 zombie-prune policy."}
        self.assertFalse(heuristic_pipeline_failure_exempt_prune("geo-gold", state))
    def test_not_exempt_on_empty_state(self):
        state = {}
        self.assertFalse(heuristic_pipeline_failure_exempt_prune("any-strategy", state))
    def test_not_exempt_when_flag_is_false(self):
        state = {"rationale": "", "pipeline_failure_suspected": False}
        self.assertFalse(heuristic_pipeline_failure_exempt_prune("crypto-momentum", state))
